import React, { useState } from "react";
import api from "../api/api"; // axios instance

const CalorieUpload = () => {
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImage(file);
    setPreview(URL.createObjectURL(file));
    setResult(null);
    setError("");
  };

  const handleUpload = async () => {
    if (!image) {
      setError("Please select an image first");
      return;
    }

    const formData = new FormData();
    formData.append("file", image);

    try {
      setLoading(true);
      const response = await api.post(
        "http://localhost:5001/predict-calories-image",
        formData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
          },
        }
      );

      setResult(response.data.prediction);
    } catch (err) {
      setError("Failed to analyze image");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-card p-6 rounded-xl shadow-md">
      <h2 className="text-xl font-semibold mb-4">
        🥗 Upload Food Image for Calorie Estimation
      </h2>

      <input
        type="file"
        accept="image/*"
        onChange={handleImageChange}
        className="mb-4"
      />

      {preview && (
        <img
          src={preview}
          alt="Preview"
          className="w-48 h-48 object-cover rounded-lg mb-4"
        />
      )}

      <button
        onClick={handleUpload}
        disabled={loading}
        className="bg-gradient-to-r from-green-500 to-emerald-500 text-white px-6 py-2 rounded-lg hover:opacity-90"
      >
        {loading ? "Analyzing..." : "Upload & Analyze"}
      </button>

      {error && <p className="text-red-500 mt-3">{error}</p>}

      {result && (
        <div className="mt-6 bg-white bg-opacity-10 p-4 rounded-lg">
          <h3 className="font-semibold mb-2">🍽️ Prediction Result</h3>
          <p><strong>Food:</strong> {result.foodName}</p>
          <p><strong>Calories:</strong> {result.caloriesEstimated} kcal</p>
          <p><strong>Confidence:</strong> {result.confidence * 100}%</p>
          <p className="text-sm text-gray-300">
            Mode: {result.mode}
          </p>
        </div>
      )}
    </div>
  );
};

export default CalorieUpload;
